/**
 * The symbol used to carry the nearest enclosing `recursive` or
 * `recursiveAsync` schema through the config object, so that `Recur` can
 * resolve to it at run time.
 */
const RECUR_RESOLVER = Symbol('recur resolver');

/**
 * The schema a `Recur` placeholder resolves to.
 */
type RecurResolver =
  | BaseSchema<unknown, unknown, BaseIssue<unknown>>
  | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>;

/**
 * Returns a new config that carries `resolver` as the current `Recur`
 * resolver.
 *
 * @param config The config to extend.
 * @param resolver The schema `Recur` should resolve to.
 *
 * @returns The extended config.
 */
// @__NO_SIDE_EFFECTS__
export function _withRecurResolver<TIssue extends BaseIssue<unknown>>(
  config: Config<TIssue>,
  resolver: RecurResolver
): Config<TIssue> {
  return { ...config, [RECUR_RESOLVER]: resolver };
}

/**
 * Returns the nearest enclosing `recursive` or `recursiveAsync` schema
 * registered on `config`, if any.
 *
 * @param config The config to read from.
 *
 * @returns The `Recur` resolver, if any.
 */
// @__NO_SIDE_EFFECTS__
export function _getRecurResolver<TIssue extends BaseIssue<unknown>>(
  config: Config<TIssue>
): RecurResolver | undefined {
  return (config as Config<TIssue> & { [RECUR_RESOLVER]?: RecurResolver })[
    RECUR_RESOLVER
  ];
}
