type InferOutput<T> = T extends Schema<unknown, infer O> ? O : never;

type RejectRecur<T> =
  Collapse<ContainsRecur<InferInput<T>>> extends true ? { readonly '~recur': never }
  : Collapse<ContainsRecur<InferOutput<T>>> extends true ? { readonly '~recur': never }
