parse(unresolved, {});

// case 3: resolved recursive schema - should be fine, and NOT hang/error on ContainsRecur
type Resolved = ResolveRecur<Inner>;
declare const resolved: Schema<Resolved, Resolved>;
parse(resolved, {});

